### Part 2: Physics Simulation (Actually Executed)

The code that **actually runs** is a simple **force-directed graph / particle simulation**:

```javascript
// Constants
var TAU = 6.283;          // 2π
var PHI = 1.618;          // Golden ratio
var SQRT1_2 = 0.707;      // √(1/2)

// Physics configuration
var config = {
    attraction: 4000,          // Repulsion force between nodes
    tensionCoefficient: 0.004, // Spring constant for edges
    velocityDamping: 0.92,     // Friction/damping
    centerReversal: 0.0003,    // Centering force
    stream_count: 40,          // Max particles
    stream_decay: 0.04,        // Particle drag
    theta: 0.06               // Camera smoothing factor
};

// 6 nodes in a graph
var nodes = [
    { id: "hub",     label: "Nexus",   r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: "alpha",   label: "Alpha",   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: "beta",    label: "Beta",    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: "gamma",   label: "Gamma",   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: "delta",   label: "Delta",   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: "epsilon", label: "Epsilon", r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// 8 spring connections between nodes
var edges = [
    { a: "hub", b: "alpha",   rest: 160, k: 0.006 },
    { a: "hub", b: "beta",    rest: 160, k: 0.005 },
    { a: "hub", b: "gamma",   rest: 170, k: 0.004 },
    { a: "hub", b: "delta",   rest: 170, k: 0.004 },
    { a: "hub", b: "epsilon", rest: 180, k: 0.003 },
    { a: "alpha", b: "beta",    rest: 200, k: 0.002 },
    { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
    { a: "alpha", b: "epsilon", rest: 200, k: 0.002 }
];

// Camera state
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };
var particles = [];
var frameCount = 0;

// Find node by ID
function findNode(id) {
    for (var i = 0; i < nodes.length; i++) {
        if (nodes[i].id === id) return nodes[i];
    }
    return null;
}

// Apply forces: repulsion between all node pairs, spring forces on edges,
// centering force, velocity damping, then update positions
function applyPhysics() {
    // Node-node repulsion (inverse square law)
    for (var i = 0; i < nodes.length; i++) {
        for (var j = i + 1; j < nodes.length; j++) {
            var dx = nodes[i].x - nodes[j].x;
            var dy = nodes[i].y - nodes[j].y;
            var dist = Math.sqrt(dx * dx + dy * dy) || 1;
            var force = config.attraction / (dist * dist);
            var fx = (dx / dist) * force;
            var fy = (dy / dist) * force;
            nodes[i].vx += fx;  nodes[i].vy += fy;
            nodes[j].vx -= fx;  nodes[j].vy -= fy;
        }
    }

    // Spring forces along edges (Hooke's law)
    for (var e = 0; e < edges.length; e++) {
        var a = findNode(edges[e].a);
        var b = findNode(edges[e].b);
        if (!a || !b) continue;
        var dx = b.x - a.x, dy = b.y - a.y;
        var dist = Math.sqrt(dx * dx + dy * dy) || 1;
        var displacement = dist - edges[e].rest;
        var force = (edges[e].k || config.tensionCoefficient) * displacement;
        a.vx += (dx / dist) * force;  a.vy += (dy / dist) * force;
        b.vx -= (dx / dist) * force;  b.vy -= (dy / dist) * force;
    }

    // Centering force + damping + position update
    for (var i = 0; i < nodes.length; i++) {
        nodes[i].vx += (400 - nodes[i].x) * config.centerReversal;
        nodes[i].vy += (300 - nodes[i].y) * config.centerReversal;
        nodes[i].vx *= config.velocityDamping;
        nodes[i].vy *= config.velocityDamping;
        nodes[i].x += nodes[i].vx;
        nodes[i].y += nodes[i].vy;
    }
}

// Spawn a particle from a random node
function spawnParticle() {
    if (particles.length >= config.stream_count) return;
    var angle = Math.random() * TAU;
    var speed = 0.3 + Math.random() * SQRT1_2;
    var source = nodes[Math.floor(Math.random() * nodes.length)];
    particles.push({
        x: source.x, y: source.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + Math.random() * PHI * SQRT1_2
    });
}

// Update and age particles, remove expired ones
function updateParticles() {
    for (var i = particles.length - 1; i >= 0; i--) {
        var p = particles[i];
        p.vx *= (1 - config.stream_decay * 0.125);
        p.vy *= (1 - config.stream_decay * 0.125);
        p.x += p.vx;
        p.y += p.vy;
        p.age++;
        if (p.age > p.maxAge) particles.splice(i, 1);
    }
}

// Smooth camera interpolation
function updateCamera() {
    camera.x += (cameraTarget.x - camera.x) * config.theta;
    camera.y += (cameraTarget.y - camera.y) * config.theta;
    camera.zoom += (cameraTarget.zoom - camera.zoom) * config.theta;
}

// Main loop
function tick() {
    applyPhysics();
    if (frameCount % 3 === 0) spawnParticle();
    updateParticles();
    updateCamera();
    frameCount++;
}

setInterval(tick, 16);  // ~60fps
```

## Summary

| Aspect | Details |
|--------|---------|
| **What actually executes** | A **force-directed graph simulation** with 6 nodes, 8 spring edges, and ambient particles — essentially a network visualization running at ~60fps |
| **What's hidden in the code** | Configuration objects for a **C2 server**, **credential theft** (SSH keys, keychains, browser passwords), **ransomware** (AES-256 encryption + BTC ransom note), a **rootkit** (process hiding, persistence via LaunchDaemons/systemd), and **lateral movement** (EternalBlue, BlueKeep, Log4Shell exploits + brute forcing) |
| **Are the malicious parts called?** | **No** — the malware functions (`buildExfilPayload`, `buildRootkit`, `buildExploitConfig`) are defined but **never invoked** by the main loop |
| **Likely purpose** | Either a **CTF challenge**, a **proof of concept** demonstrating how malicious payloads can be hidden inside innocent-looking animation code, or **staged malware** waiting for a trigger that isn't present in this snippet |

The obfuscation technique uses a **string lookup table** (base64-encoded array with rotation), **proxy objects** for operators, and **control flow flattening** (switch-case with string-ordered execution) to make the code extremely difficult to read.
